type Pin = {
  num: string;
  name: string;
  region: string;
  x: number;
  y: number;
  /** Label offset relative to marker + anchor, tuned per pin to avoid collisions */
  lx: number;
  ly: number;
  anchor: 'start' | 'middle' | 'end';
};

const pins: Pin[] = [
  { num: '01', name: 'KERINCI',    region: 'JAMBI',       x: 144.7, y: 178.7, lx: -14, ly: 4,   anchor: 'end' },
  { num: '02', name: 'PAGAR ALAM', region: 'PALEMBANG',   x: 186.2, y: 223.8, lx: -14, ly: 4,   anchor: 'end' },
  { num: '03', name: 'TANGGAMUS',  region: 'LAMPUNG',     x: 215.3, y: 252.8, lx: -14, ly: 10,  anchor: 'end' },
  { num: '04', name: 'BANJARAN',   region: 'WEST JAVA',  x: 278.5, y: 288.3, lx: -6,  ly: 24,  anchor: 'middle' },
  { num: '05', name: 'IJEN',       region: 'EAST JAVA',  x: 424.0, y: 305.5, lx: 4,   ly: -16, anchor: 'middle' },
  { num: '06', name: 'JEMBER',     region: 'EAST JAVA',  x: 404.5, y: 316.0, lx: -22, ly: 24,  anchor: 'middle' },
  { num: '07', name: 'KINTAMANI',  region: 'BALI',        x: 443.0, y: 313.8, lx: 14,  ly: 22,  anchor: 'start' },
  { num: '08', name: 'TORAJA',     region: 'SOUTH SULAWESI', x: 538.9, y: 203.8, lx: 14, ly: 4, anchor: 'start' },
];

function MapMarker({
  pin,
  index,
  active,
  onHover,
  shouldReduceMotion,
}: {
  pin: Pin;
  index: number;
  active: boolean;
  onHover: (i: number | null) => void;
  shouldReduceMotion: boolean | null;
}) {
  return (
    <motion.g
      variants={{
        hidden: shouldReduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.4 },
        visible: shouldReduceMotion ? { opacity: 1 } : { opacity: 1, scale: 1 },
      }}
      transition={{ type: 'spring', stiffness: 300, damping: 18, delay: index * 0.08 }}
      style={{ transformOrigin: `${pin.x}px ${pin.y}px`, transformBox: 'fill-box', cursor: 'pointer' }}
      onMouseEnter={() => onHover(index)}
      onMouseLeave={() => onHover(null)}
    >
      {/* Crosshair ticks */}
      {[
        [pin.x, pin.y - 13, pin.x, pin.y - 9],
        [pin.x, pin.y + 9, pin.x, pin.y + 13],
        [pin.x - 13, pin.y, pin.x - 9, pin.y],
        [pin.x + 9, pin.y, pin.x + 13, pin.y],
      ].map(([x1, y1, x2, y2], i) => (
        <line
          key={i}
          x1={x1} y1={y1} x2={x2} y2={y2}
          stroke="var(--stamp)"
          strokeWidth={1}
          opacity={active ? 1 : 0.55}
        />
      ))}

      {/* Marker circle + number */}
      <circle
        cx={pin.x}
        cy={pin.y}
        r={8.5}
        fill={active ? 'var(--stamp)' : 'var(--paper)'}
        stroke="var(--stamp)"
        strokeWidth={1.5}
        style={{ transition: 'fill 0.2s' }}
      />
      <text
        x={pin.x}
        y={pin.y + 3}
        textAnchor="middle"
        style={{
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: '8.5px',
          fontWeight: 700,
          fill: active ? 'var(--paper)' : 'var(--stamp)',
          transition: 'fill 0.2s',
          pointerEvents: 'none',
        }}
      >
        {pin.num}
      </text>

      {/* Name label */}
      <text
        x={pin.x + pin.lx}
        y={pin.y + pin.ly}
        textAnchor={pin.anchor}
        style={{
          fontFamily: "'IBM Plex Mono', monospace",
          fontSize: '11px',
          fontWeight: 600,
          letterSpacing: '0.06em',
          textTransform: 'uppercase',
          fill: active ? 'var(--stamp)' : 'var(--ink)',
          transition: 'fill 0.2s',
          pointerEvents: 'none',
        }}
      >
        {pin.name}
      </text>
    </motion.g>
  );
}

export function OriginMap() {
  const shouldReduceMotion = useReducedMotion();
  const [active, setActive] = useState<number | null>(null);

  return (
    <section
      id="map"
      className="py-20 md:py-32 paper-texture border-t border-dashed border-[var(--jute)]"
    >
      <div className="max-w-7xl mx-auto px-5 md:px-12 flex flex-col">

        {/* Section header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: '-100px' }}
          transition={{ duration: 0.6 }}
          className="mb-12 md:mb-16 flex flex-col gap-6"
        >
          <div className="flex items-center gap-4">
            <span className="font-['IBM_Plex_Mono'] text-[var(--jute)] uppercase tracking-[0.1em] text-sm font-semibold whitespace-nowrap">
              DOC 03 / ORIGIN MAP
            </span>
            <div className="flex-1" style={{ height: '1px', background: 'var(--jute)' }} />
          </div>
          <div>
            <h2
              className="font-['Archivo'] font-black uppercase text-[var(--ink)] tracking-[-0.02em] leading-[1.05] mb-2"
              style={{ fontSize: 'clamp(2rem, 4vw + 0.5rem, 3rem)' }}
            >
              ORIGIN MAP
            </h2>
            <p className="font-['IBM_Plex_Mono'] text-[var(--ink)]/60 text-sm uppercase tracking-[0.05em]">
              Eight growing regions across the Indonesian archipelago.
            </p>
          </div>
        </motion.div>

        {/* Chart — horizontally scrollable on mobile so labels stay legible */}
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: '-50px' }}
          variants={{
            hidden: { opacity: 0, y: 30 },
            visible: { opacity: 1, y: 0, transition: { duration: 0.6 } },
          }}
          className="relative overflow-x-auto carousel-scroll"
          style={{ border: '1px solid var(--ink)', WebkitOverflowScrolling: 'touch' }}
        >
          <div className="min-w-[760px] md:min-w-0 relative">
            <svg
              viewBox="0 0 1000 383"
              xmlns="http://www.w3.org/2000/svg"
              className="w-full h-auto block"
              role="img"
              aria-label="Map of Indonesia marking eight coffee growing regions: Kerinci in Jambi, Pagar Alam in Palembang, Tanggamus in Lampung, Banjaran in West Java, Ijen and Jember in East Java, Kintamani in Bali, and Toraja in South Sulawesi"
            >
              {/* Chart annotation */}
              <text
                x={14} y={26}
                style={{
                  fontFamily: "'IBM Plex Mono', monospace",
                  fontSize: '11px',
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  fill: 'var(--jute)',
                }}
              >
                FIG. 01 REPUBLIC OF INDONESIA / COFFEE GROWING REGIONS
              </text>
              <line x1={14} y1={34} x2={396} y2={34} stroke="var(--jute)" strokeWidth={1} strokeDasharray="3 3" />

              {/* Archipelago */}
              <path
                d={INDONESIA_PATH}
                fill="var(--jute)"
                fillOpacity={0.3}
                stroke="var(--ink)"
                strokeWidth={0.7}
                strokeLinejoin="round"
              />

              {/* Survey point markers */}
              {pins.map((pin, i) => (
                <MapMarker
                  key={pin.num}
                  pin={pin}
                  index={i}
                  active={active === i}
                  onHover={setActive}
                  shouldReduceMotion={shouldReduceMotion}
                />
              ))}
            </svg>
          </div>
        </motion.div>

        {/* Mobile scroll hint */}
        <p className="md:hidden font-['IBM_Plex_Mono'] text-[var(--jute)] text-xs uppercase tracking-[0.1em] mt-3 text-center">
          ← SWIPE TO EXPLORE THE CHART →
        </p>

        {/* Region manifest */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: '-50px' }}
          transition={{ duration: 0.6, delay: 0.1 }}
          className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-2 mt-8 md:mt-10"
        >
          {pins.map((pin, i) => (
            <div
              key={pin.num}
              className="flex items-baseline gap-2 py-2"
              style={{
                fontFamily: "'IBM Plex Mono', monospace",
                fontSize: '13px',
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
                borderBottom: '1px dotted var(--jute)',
                cursor: 'default',
              }}
              onMouseEnter={() => setActive(i)}
              onMouseLeave={() => setActive(null)}
            >
              <span
                className="shrink-0 font-semibold"
                style={{ color: active === i ? 'var(--stamp)' : 'var(--jute)', transition: 'color 0.2s' }}
              >
                {pin.num}
              </span>
              <span
                className="shrink-0 font-semibold"
                style={{ color: active === i ? 'var(--stamp)' : 'var(--ink)', transition: 'color 0.2s' }}
              >
                {pin.name}
              </span>
              <span
                className="flex-1 self-end"
                style={{ borderBottom: '1px dotted var(--jute)', marginBottom: '3px', minWidth: '12px', opacity: 0.5 }}
              />
              <span className="shrink-0" style={{ color: 'var(--ink)', opacity: 0.7 }}>
                {pin.region}
              </span>
            </div>
          ))}
        </motion.div>

      </div>
    </section>
  );
}
